var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"불합격이야. 이제 돌아가.","JPN":"不合格。もう帰って。","ENG":"You didn't pass. Go home.","TWN":"淘汰，你回去吧。"},"stage":{"bg":"TRAINING","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"에엣?! 아직 준비해 온 춤도 노래도 요리도 제대로 못 보여드렸는데요!","JPN":"ええっ！？　まだ準備してきたダンスも、歌も、料理もちゃんとお見せできていません！","ENG":"What?! But I still haven't shown you my dance moves, my singing skills, or my cooking!","TWN":"這麼快！？我有準備要唱歌、跳舞跟做菜欸！都還沒表演呢！"},"stage":{"bg":"TRAINING","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"그런 걸 왜 준비해 온 거야…?","JPN":"なんでそんなの準備してきたの……？","ENG":"Why did you even prepare all of that...?","TWN":"準備這種東西要幹嘛…？"},"stage":{"bg":"TRAINING","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"이미 결정난 일이야. 부모님 있는 데로 돌아가.","JPN":"もう決まったことだよ。ご両親のいるところに帰りな。","ENG":"The decision's been made. Go back to your family.","TWN":"事已成定局，你回去找你爸媽吧。"},"stage":{"bg":"TRAINING","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"그러지 말고 한 번만 더 고민해 주세요! 전 펜릴 소대에 꼭 들어가고 싶어요!","JPN":"そうおっしゃらず、もう一度だけ考えてみてください！　私、絶対フェンリル小隊に入りたいんです！","ENG":"Please, could you at least reconsider? I really want to join Fenrir Squad!","TWN":"不要這樣啦，拜託你們再考慮一下！我一定要進芬里爾小隊！"},"stage":{"bg":"TRAINING","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"분명 무슨 방법이 있을 거예요! 그렇죠?","JPN":"きっと何か方法があるはずです！　ね？","ENG":"There has to be some way, right?","TWN":"一定有什麼辦法的！有吧？"},"stage":{"bg":"TRAINING","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"가르쳐 주시면 안 돼요? 네?","JPN":"教えてもらえませんか？　ね？","ENG":"Can't you tell me? Please?","TWN":"可以告訴我嗎？拜託？"},"stage":{"bg":"TRAINING","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":null,"text":{"KOREA":"이, 일단 좀 떨어져서 얘기하게나.","JPN":"い、いったん少し離れて話してくれたまえ。","ENG":"H-how about we take a step back and then talk?","TWN":"那個，可以先保持一下安全社交距離嗎？"},"stage":{"bg":"TRAINING","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"하아. 포기할 줄을 모르네.","JPN":"はあ。諦めが悪いんだね。","ENG":"*Sigh* She's not going to give up, is she?","TWN":"哀，有夠堅持的。"},"stage":{"bg":"TRAINING","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"그럼 어디 3종 침식체라도 잡아 와.","JPN":"じゃあ、どこかで第3種侵食体でも捕まえてきて。","ENG":"Then go defeat a Category 3 C.O.","TWN":"那你抓個3類侵蝕體來看看。"},"stage":{"bg":"TRAINING","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"3종 침식체를요?","JPN":"第3種侵食体をですか？","ENG":"A Category 3 C.O.?","TWN":"3類侵蝕體嗎？"},"stage":{"bg":"TRAINING","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"그래. 어차피 살면서 한 번 마주치기도 힘들겠지만.","JPN":"そう。どうせ一生に一度出くわすかどうかだろうけど。","ENG":"Yes. Even coming across one will be a once-in-a-lifetime experience.","TWN":"沒錯，不過3類侵蝕體也不是你想遇就遇得到的。"},"stage":{"bg":"TRAINING","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"고마워요, 유미나 님!","JPN":"ありがとうございます、ミナ様！","ENG":"Thank you, Ms. Mina!","TWN":"謝謝劉米娜小姐！"},"stage":{"bg":"TRAINING","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"도전! 지금부터 3종 침식체를 잡으러 출발!","JPN":"挑戦！　今から第3種侵食体を捕まえに出発！","ENG":"Challenge accepted! Let's go get myself a Category 3 C.O.!","TWN":"挑戰！我現在就去抓3類侵蝕體！"},"stage":{"bg":"TRAINING","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"……뭐야, 쟤? 태스크포스 지원자라면서?","JPN":"……何？　あいつ。タスクフォースの志願者じゃなかったの？","ENG":"...What's up with her? Didn't you say she was a TASKFORCE applicant?","TWN":"……她有什麼問題？這樣還要應徵特遣勢力？"},"stage":{"bg":"TRAINING","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"가끔은 저렇게 세상 물정 모르는 아이들도 있어요.","JPN":"たまにあんな世間知らずな子もいるんです。","ENG":"Sometimes, there are kids who are too naive to understand the world.","TWN":"世界上確實有些人跟她一樣不知道天高地厚。"},"stage":{"bg":"TRAINING","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"입사할 때의 미나 양처럼 말이죠.","JPN":"入社したときのミナさんのように。","ENG":"Just like you when you first joined us, Mina.","TWN":"就像剛進公司時的你一樣。"},"stage":{"bg":"TRAINING","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};